import java.util.*;
import org.springframework.http.*;
import org.springframework.web.bind.annotation.*;
record Stock(String symbol, String name, double price) {}
record StockRequest(String name, double price) {}
interface StockService {
    List<Stock> findAll();
    Optional<Stock> findBySymbol(String sym);
    Stock save(String sym, StockRequest req);
    Optional<Stock> update(String sym, StockRequest req);
    boolean delete(String sym);
}
@RestController
@RequestMapping("/api/stocks")
public class StockController {
    private final StockService service;
    StockController(StockService s) { service = s; }

    @GetMapping
    public List<Stock> getAll() { return service.findAll(); }

    @GetMapping("/{symbol}")
    public ResponseEntity<Stock> getOne(@PathVariable String symbol) {
        return service.findBySymbol(symbol)
            .map(ResponseEntity::ok)
            .orElse(ResponseEntity.notFound().build());
    }

    @PostMapping("/{symbol}")
    public ResponseEntity<Stock> create(@PathVariable String symbol,
                                         @RequestBody StockRequest req) {
        return ResponseEntity.status(HttpStatus.CREATED).body(service.save(symbol, req));
    }

    @PutMapping("/{symbol}")
    public ResponseEntity<Stock> update(@PathVariable String symbol,
                                         @RequestBody StockRequest req) {
        return service.update(symbol, req)
            .map(ResponseEntity::ok)
            .orElse(ResponseEntity.notFound().build());
    }

    @DeleteMapping("/{symbol}")
    public ResponseEntity<Void> delete(@PathVariable String symbol) {
        return service.delete(symbol)
            ? ResponseEntity.noContent().build()
            : ResponseEntity.notFound().build();
    }
}

