import org.springframework.web.bind.annotation.*;

record UserRegistrationRequest(String email, String password) {}
record UserRegistrationResponse(String userId, String email, String createdAt) {}

@RestController
@RequestMapping("/api/users")
public class UserController {
    private int seq = 1;

    @PostMapping
    public ResponseEntity<UserRegistrationResponse> register(
            @RequestBody UserRegistrationRequest req) {
        String userId = "U" + String.format("%04d", seq++);
        UserRegistrationResponse response = new UserRegistrationResponse(
            userId, req.email(), LocalDateTime.now().toString());
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }
}

