import java.util.*;
import org.springframework.http.*;
import org.springframework.web.bind.annotation.*;
record PaymentRequest(String userId, double amount, String currency) {}
record Payment(String id, String userId, double amount, String currency, String status) {}
interface PaymentService {
    Payment create(PaymentRequest req);
    Optional<Payment> findById(String id);
    List<Payment> filter(String userId, String status);
    Optional<Payment> capture(String id);
}

@RestController
@RequestMapping("/api/payments")
class PaymentController {
    private final PaymentService service;
    PaymentController(PaymentService s) { service = s; }

    @PostMapping
    public ResponseEntity<Payment> create(@RequestBody PaymentRequest req) {
        return ResponseEntity.status(HttpStatus.CREATED).body(service.create(req));
    }
    @GetMapping("/{id}")
    public ResponseEntity<Payment> getById(@PathVariable String id) {
        return service.findById(id).map(ResponseEntity::ok)
            .orElse(ResponseEntity.notFound().build());
    }
    @GetMapping
    public List<Payment> filter(
            @RequestParam(required = false) String userId,
            @RequestParam(required = false) String status) {
        return service.filter(userId, status);
    }
    @PutMapping("/{id}/capture")
    public ResponseEntity<Payment> capture(@PathVariable String id) {
        return service.capture(id).map(ResponseEntity::ok)
            .orElse(ResponseEntity.notFound().build());
    }
}

