import org.junit.jupiter.api.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;
import static org.mockito.Mockito.*;
import static org.mockito.ArgumentMatchers.*;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@WebMvcTest(PaymentController.class)
class PaymentControllerTest {
    @Autowired MockMvc mvc;
    @MockBean PaymentService service;
    Payment p = new Payment("PAY-001","U01",1500,"INR","CREATED");

    @Test void create_returns201() throws Exception {
        when(service.create(any())).thenReturn(p);
        mvc.perform(post("/api/payments").contentType(MediaType.APPLICATION_JSON)
                .content("{\"userId\":\"U01\",\"amount\":1500,\"currency\":\"INR\"}"))
            .andExpect(status().isCreated()).andExpect(jsonPath("$.id").value("PAY-001"));
    }
    @Test void getById_found() throws Exception {
        when(service.findById("PAY-001")).thenReturn(Optional.of(p));
        mvc.perform(get("/api/payments/PAY-001"))
            .andExpect(status().isOk()).andExpect(jsonPath("$.status").value("CREATED"));
    }
    @Test void getById_notFound() throws Exception {
        when(service.findById("PAY-999")).thenReturn(Optional.empty());
        mvc.perform(get("/api/payments/PAY-999")).andExpect(status().isNotFound());
    }
    @Test void filter_byUserId_returnsMatching() throws Exception {
        when(service.filter(eq("U01"), any())).thenReturn(List.of(p));
        mvc.perform(get("/api/payments?userId=U01"))
            .andExpect(status().isOk()).andExpect(jsonPath("$.length()").value(1));
    }
    @Test void capture_existing_200() throws Exception {
        when(service.capture("PAY-001")).thenReturn(Optional.of(new Payment("PAY-001","U01",1500,"INR","CAPTURED")));
        mvc.perform(put("/api/payments/PAY-001/capture"))
            .andExpect(status().isOk()).andExpect(jsonPath("$.status").value("CAPTURED"));
    }
    @Test void capture_nonExistent_404() throws Exception {
        when(service.capture("PAY-999")).thenReturn(Optional.empty());
        mvc.perform(put("/api/payments/PAY-999/capture")).andExpect(status().isNotFound());
    }
}
